function solve(grid: number[][], k: number): number {
    const m = grid.length;
    const n = grid[0].length;
    const dist = Array(m).fill(0).map(() => Array(n).fill(Infinity));
    dist[0][0] = 0;

    const dirs = [[0, 1], [1, 0]]; // right, down

    const pq = new PriorityQueue<[number, number, number, number]>((a, b) => a[0] - b[0]);
    pq.enqueue([0, 0, 0, 0]); // [cost, row, col, usedTransports]

    while (!pq.isEmpty()) {
        const [cost, row, col, used] = pq.dequeue()!;
        if (row === m - 1 && col === n - 1) return cost;
        if (used > k) continue;

        // Regular moves
        for (const [dr, dc] of dirs) {
            const newRow = row + dr;
            const newCol = col + dc;
            if (newRow >= 0 && newRow < m && newCol >= 0 && newCol < n) {
                const newCost = cost + grid[newRow][newCol];
                if (newCost < dist[newRow][newCol]) {
                    dist[newRow][newCol] = newCost;
                    pq.enqueue([newCost, newRow, newCol, used]);
                }
            }
        }

        // Teleportation
        for (let i = 0; i < m; i++) {
            for (let j = 0; j < n; j++) {
                if (grid[i][j] <= grid[row][col] && i !== row && j !== col) {
                    if (cost < dist[i][j]) {
                        dist[i][j] = cost;
                        pq.enqueue([cost, i, j, used + 1]);
                    }
                }
            }
        }
    }

    return dist[m - 1][n - 1];
}

class PriorityQueue<T> {
    private heap: T[];
    private compare: (a: T, b: T) => number;

    constructor(compare: (a: T, b: T) => number) {
        this.heap = [];
        this.compare = compare;
    }

    enqueue(item: T): void {
        this.heap.push(item);
        this.heapifyUp(this.heap.length - 1);
    }

    dequeue(): T | undefined {
        if (this.heap.length === 0) return undefined;
        const item = this.heap[0];
        this.heap[0] = this.heap.pop()!;
        this.heapifyDown(0);
        return item;
    }

    isEmpty(): boolean {
        return this.heap.length === 0;
    }

    private heapifyUp(index: number): void {
        while (index > 0) {
            const parentIndex = Math.floor((index - 1) / 2);
            if (this.compare(this.heap[index], this.heap[parentIndex]) >= 0) {
                [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
                index = parentIndex;
            } else {
                break;
            }
        }
    }

    private heapifyDown(index: number): void {
        const leftChild = 2 * index + 1;
        const rightChild = 2 * index + 2;
        let smallest = index;

        if (leftChild < this.heap.length && this.compare(this.heap[leftChild], this.heap[smallest]) < 0) {
            smallest = leftChild;
        }

        if (rightChild < this.heap.length && this.compare(this.heap[rightChild], this.heap[smallest]) < 0) {
            smallest = rightChild;
        }

        if (smallest !== index) {
            [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
            this.heapifyDown(smallest);
